import { handlePlayerData } from "./pages/player";
import { initNavigationHandler } from "./navigation-handler";
import { handleRosterData } from "./pages/roster";
import { handleUserData, User } from "./user";
import { handleDraftClassData } from "./pages/draft-class";
import { handleDraftRankingData, handleDraftPickData, } from "./pages/draft-ranking";
import { handleCoachMarketData } from "./pages/coach-market";
import { handleFreeAgentCenterData } from "./pages/free-agent-center";
import { handleCoachingStaffData } from "./pages/coaching-staff";
import { handleTradeCenterData } from "./pages/trade-center";
(function () {
    initNavigationHandler(); // Initialize Observer from script context
    window.userData = new User(); // Initialize User Object with default settings, probably not needed but fixes some load inconsistencies
    const URL_HANDLERS = {
        player: {
            pattern: /\/api\/player\/[^\/]+$/,
            handler: (data) => {
                handlePlayerData(data.data);
            },
        },
        roster: {
            pattern: /\/api\/team\/[^\/]+\/roster/,
            handler: (data) => {
                handleRosterData(data.data);
            },
        },
        draftClass: {
            pattern: /\/api\/league\/[^\/]+\/draft-class/,
            handler: (data) => {
                handleDraftClassData(data.data);
            },
        },
        userInfo: {
            pattern: /\/api\/user$/,
            handler: (data) => {
                handleUserData(data);
            },
        },
        draftRanking: {
            pattern: /\/api\/draft\/[^\/]+\/rankings/,
            handler: (data) => {
                handleDraftRankingData(data.data);
            },
        },
        draftPicks: {
            pattern: /\/api\/draft\/[^\/]+\/picks/,
            handler: (data) => {
                handleDraftPickData(data.data);
            },
        },
        coachingStaff: {
            pattern: /\/api\/club\/[^\/]+\/coaching-staff/,
            handler: (data) => {
                handleCoachingStaffData(data.data);
            },
        },
        coachMarket: {
            pattern: /\/api\/coach-center\/search/,
            handler: (data) => {
                handleCoachMarketData(data.data);
            },
        },
        freeAgentCenter: {
            pattern: /\/api\/free-agent-center\/search/,
            handler: (data) => {
                handleFreeAgentCenterData(data.data);
            },
        },
        tradeCenter: {
            pattern: /\/api\/trade-center\/search/,
            handler: (data) => {
                handleTradeCenterData(data.data);
            },
        },
    };
    function findHandler(url) {
        for (const { pattern, handler } of Object.values(URL_HANDLERS)) {
            if (pattern.test(url))
                return handler;
        }
        return null;
    }
    class Interceptor extends XMLHttpRequest {
        interceptedUrl = null;
        // @ts-ignore
        open(method, url, ...rest) {
            this.interceptedUrl = url;
            // @ts-ignore
            super.open(method, url, ...rest);
        }
        send(...args) {
            const url = this.interceptedUrl ?? "";
            const handler = findHandler(this.interceptedUrl ?? "");
            if (handler) {
                const originalOnReadyState = this.onreadystatechange;
                this.onreadystatechange = function () {
                    if (this.readyState === 4 && this.status === 200) {
                        try {
                            const data = JSON.parse(this.responseText);
                            handler(data);
                        }
                        catch (e) {
                            // most likely a null response body
                        }
                    }
                    if (originalOnReadyState) {
                        // @ts-ignore
                        originalOnReadyState.apply(this, arguments);
                    }
                };
            }
            super.send(...args);
        }
    }
    window.XMLHttpRequest = Interceptor;
    // intercept fetch as well, although I don't think this is used
    const originalFetch = window.fetch;
    window.fetch = async function (resource, init) {
        // handle strings & request obj
        const url = typeof resource === "string"
            ? resource
            : resource instanceof Request
                ? resource.url
                : resource.toString();
        const response = await originalFetch.call(this, resource, init);
        const handler = url && findHandler(url);
        if (handler) {
            try {
                const clonedResponse = response.clone();
                const data = await clonedResponse.json();
                handler(data);
            }
            catch (e) {
                console.error("Error processing fetch response:", e);
            }
        }
        return response;
    };
})();
